  const ayahs: AyahProps[] = [
    { ayahId: 22, surahNumber: 1, pageNumber: 1, isComplete: true, continuesFromPrev: true, textData: "۰لذِيـنَ \"شْتَرَوُاْ ۴لضَّچَلَةَ بِالْهُدۭيٰ فَمَا رَبِحَت تِّجَــٰرَتُهُمْ وَمَا كَانُواْ مُهْتَدِينَؐ ®" },
    { ayahId: 23, surahNumber: 1, pageNumber: 1, isComplete: true, continuesFromPrev: false, textData: "مَثَلُهُمْ كَمَثَلِ ۱ﻟ﮲ 'سْتَوْقَدَ نَاراً فَلَمَّآ أَضَآءَتْ مَا حَوْلَهُؐ„ ذَهَــبَ ۰للَّهُ بِنُورۣهِمْ وَتَرَكَهُمْ فِى ظُلُمَــٰــتٍ لاَّ يُبْصِرُونَؐ" },
    { ayahId: 24, surahNumber: 1, pageNumber: 1, isComplete: true, continuesFromPrev: false, textData: "صُمّٛ بُكْم٘ عُمْيٌ فَهُمْ لاَ يَرْجِعُونَؐ" },
    { ayahId: 25, surahNumber: 1, pageNumber: 1, isComplete: true, continuesFromPrev: false, textData: "أَوْ كَصَيِّبٍ مِّنَ ۰لسَّمَآءِ فِيهِ ظُلُمَـٰتٌ وَرَعْدٌ وَبَرْقٌؐ يَجْعَلُونَ أَصَــٰبِعَهُمْ فِىٓ ءَاذَانِهِم مِّـنَ ۰لصَّوَ؛عِقِ حَذَرَ ۰لْمَوْتِؐ وَاللَّهُ مُحِيطٛ بِالْكۭـٰفِـرۣينَؐ" },
    { ayahId: 26, surahNumber: 1, pageNumber: 1, isComplete: true, continuesFromPrev: false, textData: "يَكَادُ ۴لْبَرْقُ يَخْطَفُ أَبْصَـٰرَهُمْؐ كُلَّمَآ أَضَآءَ لَهُم مَّشَوْاْ فِيهِؐ وَإِذَآ أَظْلَمَ عَلَيْهِمْ قَامُواْؐ وَلَوْ شَآءَ ۰للَّهُ لَذَهَــبَ بِسَمْعِهِمْ وَأَبْصۭـٰرۣهِمُؐ; إِنَّ ۰للَّهَ عَلَيٰ كُلِّ شَيْءٍ قَدِيرٌؐ" },
    { ayahId: 27, surahNumber: 1, pageNumber: 1, isComplete: true, continuesFromPrev: false, textData: "يَـٰٓأَيُّهَا ۰لنَّاسُ ۶عْبُدُواْ رَبَّكُمُ ۴ﻟ﮲ خَلَقَكُمْ وَالذِينَ مِن قَبْلِكُمْ لَعَلَّكُمْ تَتَّقُونَؐ" },
    { ayahId: 28, surahNumber: 1, pageNumber: 1, isComplete: true, continuesFromPrev: false, textData: "۰ﻟ﮲ جَعَلَ لَكُمُ ۴لاَرْضَ فِرَ؛شاً وَالسَّمَآءَ بِنَآءً وَأَنزَلَ مِنَ ۰لسَّمَآءِ مَآءً فَأَخْرَجَ بِهِ” مِنَ ۰لثَّمَرَ؛تِ رۣزْقاً لَّكُمْؐ فَلاَ تَجْعَلُواْ لِلهِ أَندَاداً وَأَنتُمْ تَعْلَمُونَؐ" },
    { ayahId: 29, surahNumber: 1, pageNumber: 1, isComplete: false, continuesFromPrev: false, textData: "وَإِن كُنتُمْ فِى رَيْــبٍ مِّمَّا نَزَّلْنَا عَلَيٰ" }
  ];

